1	type Item = {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	};
7	type Customer = { yearsWithMHPCO: number };
8	type QuoteStep = { op: "quote"; items: Item[] };
9	type Damage = { itemType: string; amount: number };
10	type ClaimStep = {
11	  op: "claim";
12	  policy: number;
13	  incident: { cause: string; damages: Damage[] };
14	};
15	type Step = QuoteStep | ClaimStep;
16	type Scenario = {
17	  customer: Customer;
18	  steps: Step[];
19	};
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
23	const CURSE_SURCHARGE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	const LOYALTY_THRESHOLD_YEARS = 2;
28	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
29	const ITEM_BASE: Record<string, number> = {
30	  sword: 100,
31	  amulet: 60,
32	  staff: 80,
33	  potion: 40,
34	  rune: 25,
35	  moonstone: 25,
36	};
37	const ITEM_INSURANCE_VALUE: Record<string, number> = {
38	  sword: 1000,
39	  amulet: 600,
40	  staff: 800,
41	  potion: 400,
42	  rune: 250,
43	  moonstone: 250,
44	};
45	const DEDUCTIBLE = 100;
46	const CAP_MULTIPLIER = 2;
47	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
48	const HIGH_ENCHANTMENT_DAMAGE_THRESHOLD = 8;
49	
50	const COMPONENT_BLOCK_SIZE = 3;
51	const COMPONENT_BLOCK_BASE = 60;
52	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
53	
54	const countByKey = <T>(values: T[], keyOf: (value: T) => string): Map<string, number> => {
55	  const counts = new Map<string, number>();
56	  for (const value of values) {
57	    const key = keyOf(value);
58	    counts.set(key, (counts.get(key) ?? 0) + 1);
59	  }
60	  return counts;
61	};
62	
63	const groupCountsByType = (items: Item[]): Map<string, number> =>
64	  countByKey(items, (item) => item.type);
65	
66	const baseForGroup = (type: string, count: number): number => {
67	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
68	    return COMPONENT_BLOCK_BASE;
69	  }
70	  return count * ITEM_BASE[type];
71	};
72	
73	const calculatePolicyBase = (items: Item[]): number => {
74	  let total = 0;
75	  for (const [type, count] of groupCountsByType(items)) {
76	    total += baseForGroup(type, count);
77	  }
78	  return total;
79	};
80	
81	const roundUpInMHPCOsFavor = (amount: number): number => Math.ceil(amount);
82	
83	type ItemSurcharge = { applies: (item: Item) => boolean; rate: number };
84	
85	const ITEM_SURCHARGES: ItemSurcharge[] = [
86	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
87	  {
88	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
89	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
90	  },
91	];
92	
93	const surchargesForItem = (item: Item): number => {
94	  const itemBase = ITEM_BASE[item.type];
95	  return ITEM_SURCHARGES.reduce(
96	    (sum, { applies, rate }) => sum + (applies(item) ? itemBase * rate : 0),
97	    0,
98	  );
99	};
100	
101	const itemSpecificSurcharges = (items: Item[]): number =>
102	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
103	
104	type PolicyContext = { customer: Customer; quoteIndex: number };
105	
106	type PolicyModifier = {
107	  applies: (context: PolicyContext) => boolean;
108	  signedRate: number;
109	};
110	
111	const POLICY_MODIFIERS: PolicyModifier[] = [
112	  { applies: () => true, signedRate: +FIRST_CONTRACT_SURCHARGE_RATE },
113	  {
114	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
115	    signedRate: -LOYALTY_DISCOUNT_RATE,
116	  },
117	  {
118	    applies: ({ quoteIndex }) => quoteIndex > 0,
119	    signedRate: -FOLLOW_UP_DISCOUNT_RATE,
120	  },
121	];
122	
123	const policyWideAdjustment = (policyBase: number, context: PolicyContext): number =>
124	  POLICY_MODIFIERS.reduce(
125	    (sum, { applies, signedRate }) => sum + (applies(context) ? policyBase * signedRate : 0),
126	    0,
127	  );
128	
129	const quotePremium = (items: Item[], context: PolicyContext): number => {
130	  const policyBase = calculatePolicyBase(items);
131	  return roundUpInMHPCOsFavor(
132	    policyBase +
133	      itemSpecificSurcharges(items) +
134	      policyWideAdjustment(policyBase, context) +
135	      PROCESSING_FEE,
136	  );
137	};
138	
139	const insuranceSum = (items: Item[]): number =>
140	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
141	
142	const roundDownInMHPCOsFavor = (amount: number): number => Math.floor(amount);
143	
144	type Policy = { items: Item[]; remainingCap: number };
145	type QuoteResult = { premium: number };
146	type ClaimResult = { payout: number; remainingCap: number };
147	
148	const reimbursableDamage = (damage: Damage, item: Item): number =>
149	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_DAMAGE_THRESHOLD
150	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
151	    : damage.amount;
152	
153	const payoutForDamage = (damage: Damage, item: Item): number =>
154	  Math.max(reimbursableDamage(damage, item) - DEDUCTIBLE, 0);
155	
156	const findInsuredItem = (policy: Policy, itemType: string): Item =>
157	  policy.items.find((item) => item.type === itemType) as Item;
158	
159	const sumPayouts = (policy: Policy, damages: Damage[]): number =>
160	  damages.reduce(
161	    (sum, damage) => sum + payoutForDamage(damage, findInsuredItem(policy, damage.itemType)),
162	    0,
163	  );
164	
165	const validateDamagesAgainstPolicy = (policy: Policy, damages: Damage[]): void => {
166	  const insuredCounts = groupCountsByType(policy.items);
167	  const damageCounts = countByKey(damages, (damage) => damage.itemType);
168	  for (const [type, count] of damageCounts) {
169	    if (count > (insuredCounts.get(type) ?? 0)) {
170	      throw new Error(`claim references ${count} ${type}(s) but policy covers fewer`);
171	    }
172	  }
173	};
174	
175	const processClaim = (policy: Policy, step: ClaimStep): ClaimResult => {
176	  validateDamagesAgainstPolicy(policy, step.incident.damages);
177	  const claimedAmount = sumPayouts(policy, step.incident.damages);
178	  const payout = roundDownInMHPCOsFavor(Math.min(claimedAmount, policy.remainingCap));
179	  policy.remainingCap -= payout;
180	  return { payout, remainingCap: policy.remainingCap };
181	};
182	
183	const openPolicy = (items: Item[]): Policy => ({
184	  items,
185	  remainingCap: CAP_MULTIPLIER * insuranceSum(items),
186	});
187	
188	const validateKnownItemTypes = (items: Item[]): void => {
189	  for (const item of items) {
190	    if (!(item.type in ITEM_BASE)) {
191	      throw new Error(`unknown item type: ${item.type}`);
192	    }
193	  }
194	};
195	
196	const handleQuote = (
197	  step: QuoteStep,
198	  customer: Customer,
199	  policies: Policy[],
200	): QuoteResult => {
201	  validateKnownItemTypes(step.items);
202	  const quoteIndex = policies.length;
203	  policies.push(openPolicy(step.items));
204	  return { premium: quotePremium(step.items, { customer, quoteIndex }) };
205	};
206	
207	const handleClaim = (step: ClaimStep, policies: Policy[]): ClaimResult =>
208	  processClaim(policies[step.policy], step);
209	
210	export const runScenario = ({ customer, steps }: Scenario): {
211	  results: (QuoteResult | ClaimResult)[];
212	} => {
213	  const policies: Policy[] = [];
214	  const results = steps.map((step): QuoteResult | ClaimResult =>
215	    step.op === "quote"
216	      ? handleQuote(step, customer, policies)
217	      : handleClaim(step, policies),
218	  );
219	  return { results };
220	};
